'use strict'

/**
 * @typedef {Object} Parsers
 * @property {Function} json JSON parser
 * @property {Function} raw Raw parser
 * @property {Function} text Text parser
 * @property {Function} urlencoded URL-encoded parser
 */

/**
 * Module exports.
 * @type {Function & Parsers}
 */
exports = module.exports = bodyParser

/**
 * JSON parser.
 * @public
 */
exports.json = require('body-parser/json')

/**
 * Raw parser.
 * @public
 */
exports.raw = require('body-parser/raw')

/**
 * Text parser.
 * @public
 */
exports.text = require('body-parser/text')

/**
 * URL-encoded parser.
 * @public
 */
exports.urlencoded = require('body-parser/urlencoded')

/**
 * Create a middleware to parse json and urlencoded bodies.
 *
 * @deprecated
 * @public
 */
function bodyParser() {
  throw new Error('The bodyParser() generic has been split into individual middleware to use instead.')
}
